<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Kanban Board</title>
    <style>
        :root {
            --bg-body: #f4f5f7;
            --bg-column: #ebecf0;
            --bg-card: #ffffff;
            --text-primary: #172b4d;
            --text-secondary: #5e6c84;
            --border-color: #dfe1e6;
            --primary-btn: #0079bf;
            --danger-btn: #eb5a46;
            --shadow-sm: 0 1px 3px rgba(0,0,0,0.12);
            --shadow-md: 0 4px 6px rgba(0,0,0,0.1);
        }

        * { box-sizing: border-box; }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: var(--bg-body);
            color: var(--text-primary);
            margin: 0;
            padding: 20px;
            height: 100vh;
            display: flex;
            flex-direction: column;
        }

        header {
            margin-bottom: 20px;
            font-size: 1.5rem;
            font-weight: bold;
        }

        /* Input Area */
        .input-area {
            display: flex;
            gap: 10px;
            margin-bottom: 20px;
            background: var(--bg-card);
            padding: 10px;
            border-radius: 8px;
            box-shadow: var(--shadow-sm);
        }

        #new-card {
            flex-grow: 1;
            padding: 10px;
            border: 2px solid var(--border-color);
            border-radius: 4px;
            font-size: 1rem;
            outline: none;
        }

        #new-card:focus {
            border-color: var(--primary-btn);
        }

        #add-card {
            padding: 8px 16px;
            background-color: var(--primary-btn);
            color: white;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: bold;
        }

        #add-card:hover {
            background-color: #026aa7;
        }

        /* Board Layout */
        .board {
            display: flex;
            gap: 20px;
            overflow-x: auto;
            height: 100%;
            align-items: flex-start;
        }

        .column {
            background-color: var(--bg-column);
            min-width: 300px;
            width: 300px;
            border-radius: 8px;
            padding: 10px;
            display: flex;
            flex-direction: column;
            max-height: 100%;
        }

        .column-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 10px;
            font-weight: bold;
            color: var(--text-secondary);
            text-transform: uppercase;
            font-size: 0.85rem;
        }

        .count {
            background-color: rgba(9, 30, 66, 0.08);
            padding: 2px 8px;
            border-radius: 10px;
            font-size: 0.8rem;
        }

        .card-list {
            flex-grow: 1;
            min-height: 50px; /* Placeholder height */
            overflow-y: auto;
            padding-bottom: 10px;
        }

        /* Card Styling */
        .card {
            background-color: var(--bg-card);
            border-radius: 4px;
            padding: 10px;
            margin-bottom: 8px;
            box-shadow: var(--shadow-sm);
            cursor: grab;
            position: relative;
            transition: transform 0.2s, box-shadow 0.2s;
        }

        .card:hover {
            box-shadow: var(--shadow-md);
        }

        .card.dragging {
            opacity: 0.5;
            cursor: grabbing;
        }

        .card-title {
            font-size: 1rem;
            margin-bottom: 8px;
            word-break: break-word;
        }

        .card-del {
            position: absolute;
            top: 5px;
            right: 5px;
            background: none;
            border: none;
            color: #ccc;
            cursor: pointer;
            font-size: 1.2rem;
            line-height: 1;
            padding: 0;
        }

        .card-del:hover {
            color: var(--danger-btn);
        }
    </style>
</head>
<body>

    <header>Kanban Board</header>

    <div class="input-area">
        <input type="text" id="new-card" placeholder="Enter a new task..." autocomplete="off">
        <button id="add-card">Add Card</button>
    </div>

    <div class="board">
        <!-- Column: To Do -->
        <div id="col-todo" class="column" data-column="todo">
            <div class="column-header">
                <span>To Do</span>
                <span class="count">0</span>
            </div>
            <div class="card-list"></div>
        </div>

        <!-- Column: Doing -->
        <div id="col-doing" class="column" data-column="doing">
            <div class="column-header">
                <span>In Progress</span>
                <span class="count">0</span>
            </div>
            <div class="card-list"></div>
        </div>

        <!-- Column: Done -->
        <div id="col-done" class="column" data-column="done">
            <div class="column-header">
                <span>Done</span>
                <span class="count">0</span>
            </div>
            <div class="card-list"></div>
        </div>
    </div>

    <script>
        // --- State Management ---

        const STORAGE_KEY = 'kanban_board_state';

        let state = {
            cards: [] // Array of objects: { id, text, column }
        };

        // Initialize state from localStorage or empty
        function init() {
            try {
                const savedState = localStorage.getItem(STORAGE_KEY);
                if (savedState) {
                    state = JSON.parse(savedState);
                }
            } catch (e) {
                console.error("Failed to load state:", e);
                state = { cards: [] };
            }
            render();
        }

        // --- Persistence ---

        function save() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
        }

        // --- DOM Elements ---

        const inputEl = document.getElementById('new-card');
        const addBtn = document.getElementById('add-card');

        const colTodo = document.getElementById('col-todo');
        const colDoing = document.getElementById('col-doing');
        const colDone = document.getElementById('col-done');

        // --- Actions ---

        function generateId() {
            return Date.now().toString(36) + Math.random().toString(36).substr(2);
        }

        function addCard() {
            const text = inputEl.value.trim();
            if (!text) return;

            const newCard = {
                id: generateId(),
                text: text,
                column: 'todo' // Default to To Do
            };

            state.cards.push(newCard);

            // Clear input
            inputEl.value = '';
            inputEl.focus();

            save();
            render();
        }

        function deleteCard(cardId) {
            state.cards = state.cards.filter(card => card.id !== cardId);
            save();
            render();
        }

        function moveCard(cardId, newColumn) {
            const card = state.cards.find(c => c.id === cardId);
            if (card) {
                card.column = newColumn;
                save();
                render();
            }
        }

        // --- Rendering ---

        function render() {
            // Clear all columns
            colTodo.querySelector('.card-list').innerHTML = '';
            colDoing.querySelector('.card-list').innerHTML = '';
            colDone.querySelector('.card-list').innerHTML = '';

            // Update counts and populate cards
            const cols = [colTodo, colDoing, colDone];

            state.cards.forEach(card => {
                const cardEl = createCardElement(card);

                if (card.column === 'todo') colTodo.querySelector('.card-list').appendChild(cardEl);
                else if (card.column === 'doing') colDoing.querySelector('.card-list').appendChild(cardEl);
                else if (card.column === 'done') colDone.querySelector('.card-list').appendChild(cardEl);
            });

            // Update counts
            cols.forEach(col => {
                const count = state.cards.filter(c => c.column === col.dataset.column).length;
                col.querySelector('.count').textContent = count;
            });
        }

        function createCardElement(card) {
            const div = document.createElement('div');
            div.className = 'card';
            div.draggable = true;
            div.id = card.id;

            // Content
            const titleSpan = document.createElement('span');
            titleSpan.className = 'card-title';
            titleSpan.textContent = card.text;

            const delBtn = document.createElement('button');
            delBtn.className = 'card-del';
            delBtn.innerHTML = '&times;';
            delBtn.title = 'Delete';

            // Events
            div.addEventListener('dragstart', handleDragStart);
            div.addEventListener('click', (e) => {
                if(e.target !== delBtn) {
                    // Optional: Click to move? Prompt implies drag only, but click is common. 
                    // Sticking strictly to prompt: Drag and Drop.
                }
            });

            div.appendChild(titleSpan);
            div.appendChild(delBtn);

            deleteCard(card.id);
            return div;
        }

        // --- Drag and Drop Logic ---

        let draggedCardId = null;

        function handleDragStart(e) {
            draggedCardId = e.target.id;
            e.target.classList.add('dragging');
            e.dataTransfer.effectAllowed = 'move';
            // Set data to help debugging or if needed, though we use ID matching
            e.dataTransfer.setData('text/plain', draggedCardId); 
        }

        function handleDragEnd(e) {
            e.target.classList.remove('dragging');
            draggedCardId = null;
        }

        // Attach drag events to columns (drop zones)
        [colTodo, colDoing, colDone].forEach(col => {
            col.addEventListener('dragover', (e) => {
                e.preventDefault(); // Necessary to allow dropping
                e.dataTransfer.dropEffect = 'move';
            });

            col.addEventListener('drop', (e) => {
                e.preventDefault();

                if (!draggedCardId) return;

                const targetColumn = e.currentTarget.dataset.column;
                moveCard(draggedCardId, targetColumn);
            });
        });

        // --- Event Listeners ---

        addBtn.addEventListener('click', addCard);

        inputEl.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') addCard();
        });

        // Start
        init();

    </script>
</body>
</html>
